TriggerOraclev10g.body:
DECLARE 
envbq_status number;
valor_envbq_update number;
vro_error  tkr_errores%ROWTYPE;
BEGIN
    -- Caso INSERT
    IF INSERTING THEN

        SELECT (SELECT ENVIO_BQ FROM TKRBQ_USUARIOS_ENTIDAD WHERE ID = :NEW.ID AND ENVIO_BQ != 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_USUARIOS_ENTIDAD WHERE ID = :NEW.ID AND ENVIO_BQ != 1;
       END IF;    

        INSERT INTO TKRBQ_USUARIOS_ENTIDAD (
            ENVIO_BQ, ID, ID_ENTIDAD, ID_USUARIO, ID_PARENTESCO,
            RELACION_USUARIO, ID_CONVENIO, FECHA_CREACION, CALIFICACION_GLOBAL
        )
        VALUES (
            0, -- ENVIO_BQ para INSERT
            :NEW.ID, :NEW.ID_ENTIDAD, :NEW.ID_USUARIO, :NEW.ID_PARENTESCO,
            :NEW.RELACION_USUARIO, :NEW.ID_CONVENIO, :NEW.FECHA_CREACION, :NEW.CALIFICACION_GLOBAL
        );
    END IF;

    -- Caso UPDATE
    IF UPDATING THEN
        SELECT (SELECT ENVIO_BQ FROM TKRBQ_USUARIOS_ENTIDAD WHERE ID = :NEW.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NULL THEN

            INSERT INTO TKRBQ_USUARIOS_ENTIDAD (
                ENVIO_BQ, ID, ID_ENTIDAD, ID_USUARIO, ID_PARENTESCO,
                RELACION_USUARIO, ID_CONVENIO, FECHA_CREACION, CALIFICACION_GLOBAL
            )
            VALUES (
                2, -- ENVIO_BQ para INSERT
                :NEW.ID, :NEW.ID_ENTIDAD, :NEW.ID_USUARIO, :NEW.ID_PARENTESCO,
                :NEW.RELACION_USUARIO, :NEW.ID_CONVENIO, :NEW.FECHA_CREACION, :NEW.CALIFICACION_GLOBAL
            );


       ELSE   

            IF envbq_status = 0 THEN 
                valor_envbq_update := 0;
            ELSE
                valor_envbq_update := 2;
            END IF;    

            UPDATE TKRBQ_USUARIOS_ENTIDAD
            SET
                ENVIO_BQ = valor_envbq_update,
                ID = :NEW.ID,
                ID_ENTIDAD = :NEW.ID_ENTIDAD,
                ID_USUARIO = :NEW.ID_USUARIO,
                ID_PARENTESCO = :NEW.ID_PARENTESCO,
                RELACION_USUARIO = :NEW.RELACION_USUARIO,
                ID_CONVENIO = :NEW.ID_CONVENIO,
                FECHA_CREACION = :NEW.FECHA_CREACION,
                CALIFICACION_GLOBAL = :NEW.CALIFICACION_GLOBAL
            WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
        END IF;
    END IF;

    -- Caso DELETE
    IF DELETING THEN
        SELECT (SELECT ENVIO_BQ FROM TKRBQ_USUARIOS_ENTIDAD WHERE ID = :OLD.ID AND ENVIO_BQ != 1 AND ROWNUM <= 1) INTO envbq_status FROM DUAL;

       IF envbq_status IS NOT NULL THEN
        DELETE TKRBQ_USUARIOS_ENTIDAD WHERE ID = :OLD.ID AND ENVIO_BQ != 1;
       END IF;


        INSERT INTO TKRBQ_USUARIOS_ENTIDAD (
            ENVIO_BQ, ID, ID_ENTIDAD, ID_USUARIO, ID_PARENTESCO,
            RELACION_USUARIO, ID_CONVENIO, FECHA_CREACION, CALIFICACION_GLOBAL
        )
        VALUES (
            -1, -- ENVIO_BQ para DELETE
            :OLD.ID, :OLD.ID_ENTIDAD, :OLD.ID_USUARIO, :OLD.ID_PARENTESCO,
            :OLD.RELACION_USUARIO, :OLD.ID_CONVENIO, :OLD.FECHA_CREACION, :OLD.CALIFICACION_GLOBAL
        );
    END IF;

    EXCEPTION
        WHEN OTHERS
        THEN
            vro_error.nombre_programa := 'TRG_SYNC_TKR_USUARIOS_ENTIDAD';
            vro_error.nombre_metodo := 'TRIGGER_SYNC_BQ';
            vro_error.parametros := 'id de consultas: '||:old.id;
            uti_ge_excepciones_pkg.p_grabar_log (vro_error);

END;
